import java.util.ArrayList;import java.util.Comparator;import java.util.List;import java.util.Map;
final class HedgedRequestsPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}record Candidate(int time,String name){}@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){if(!Boolean.TRUE.equals(input.get("idempotent")))throw new PatternException("hedge_not_allowed");Map<String,Object>primary=(Map<String,Object>)input.get("primary");int delay=((Number)input.get("hedge_delay_ms")).intValue(),primaryLatency=((Number)primary.get("latency_ms")).intValue();if(primary.get("result").equals("success")&&primaryLatency<=delay)return Map.of("winner","primary","completed_ms",primaryLatency,"attempts",1,"cancelled",List.of());int start=primary.get("result").equals("failure")?Math.min(delay,primaryLatency):delay;Map<String,Object>hedge=(Map<String,Object>)input.get("hedge");List<Candidate>values=new ArrayList<>();if(primary.get("result").equals("success"))values.add(new Candidate(primaryLatency,"primary"));if(hedge.get("result").equals("success"))values.add(new Candidate(start+((Number)hedge.get("latency_ms")).intValue(),"hedge"));if(values.isEmpty())throw new PatternException("all_attempts_failed");Candidate winner=values.stream().min(Comparator.comparingInt(Candidate::time)).orElseThrow();List<String>cancelled=values.stream().filter(v->!v.name().equals(winner.name())&&winner.time()<v.time()).map(Candidate::name).toList();return Map.of("winner",winner.name(),"completed_ms",winner.time(),"attempts",2,"cancelled",cancelled);}}
